INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Hâfidh Ibn Hibbân dit que Allâh est sans endroit et qu’Il ne dépend pas du temps', 'Les Chafi''ites', 'الحمد لله الذي ليس له حدٌّ محدودٌ فيُحتوى ، ولا له أجلٌ معدودٌ فيَفنى ، ولا يحيط به جوامع الـمكان ، ولا يشتمل عليه تواتر الزمان', 'La louange est à Allâh, Celui Qui est exempt de limite et Qui n’est donc pas limité pour être contenu, Qui est exempt de terme et n’est donc pas décompté pour être anéanti, Qui n’est cerné par aucun des endroits et Qui n’est pas sujet à l’écoulement du temps', '', 'Le Hâfidh Ibnou Hibbân dans son livre « Ath-Thiqât » (tome 1, page 1) a dit :
Informations utiles :
– Le Hâfidh Aboû Hâtim Mouhammad Ibnou Hibbân Ibnou Ahmad At-Tamîmi Al-Bousti, est un savant du Salaf, il est né en 270 et il est décédé en 354 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 1080 ans. Il est un grand spécialiste de la science du Hadîth. Il est l’auteur du « Sahîh » réputé sous le nom de « Sahîh Ibn Hibbân ». Il était du madh-hab (Ecole de jurisprudence) de l’Imâm Ach-Châfi’i.
– Dans l’introduction de son livre « Ath-Thiqât », il dit que Allâh est sans endroit et qu’Il ne dépend pas du temps.', 'ahlou s-sounnah, ahlou sounnah, allah, allah est sans endroit / sans direction'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'الحمد لله الذي ليس له حدٌّ محدودٌ فيُحتوى ، ولا له أجلٌ معدودٌ فيَفنى ، ولا يحيط به جوامع الـمكان ، ولا يشتمل عليه تواتر الزمان');

