INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Précieuse parole de tawhîd de Aboû Bakr As-Siddîq', 'Les Chafi''ites', 'العَجْزُ عن دَرَكِ الإِدْرَاكِ إِدْرَاكُ والبَحْثُ عن ذَاتِهِ كُفْرٌ وإِشْرَاكُ', 'Reconnaître son incapacité à parvenir à connaître l’Être de Allâh est en soi une connaissance et chercher à concevoir Son Être est de la mécréance et de l’association', '', 'Le Calife Aboû Bakr As-Siddîq (رضي الله عنه) a dit :
[Rapporté par l’Imâm Badrou d-Dîn Az-Zarkachi dans son livre « Tachnîfou l-Maçâmi'' »]
Informations utiles :
– Aboû Bakr As-Siddîq est né 3 ans environ après l’année dite de l’éléphant et il est décédé en l’an 13 de l’Hégire (رضي الله عنه).
– Il est le meilleur homme après les Prophètes et donc le meilleur de tous les saints de toutes les communautés.
– Il est le premier homme à avoir cru et suivi le Prophète Mouhammad (صلى الله عليه وسلم).
– Il a été le premier calife bien guidé.
– Allâh ta’âlâ dit dans le Qour-ân:', '3aqidah, abou, ahlou s-sounnah, allah'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'العَجْزُ عن دَرَكِ الإِدْرَاكِ إِدْرَاكُ والبَحْثُ عن ذَاتِهِ كُفْرٌ وإِشْرَاكُ');

