INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Précieuse parole de tawhîd de Aboû Bakr As-Siddîq', 'Les Chafi''ites', '﴾ وَلاَ يُحِيطُونَ بِهِ عِلْمًا ﴿', '', '', '[Ce qui a pour sens : ]« Ils ne cernent pas Sa Réalité », [soûrat Tâhâ verset 110].
– Les créatures ne connaissent pas la réalité de Allâh, Seul Allâh sait Sa Réalité. Ainsi nous ne connaissons pas la Réalité de Allâh, de même les Prophètes et les anges ne connaissent pas la Réalité de Allâh, Seul Allâh sait Sa Réalité et il n’est pas permis de dire comment au sujet de Allâh.
– Notre connaissance de Allâh a lieu en connaissant les attributs obligatoire à Son Sujet tel que la Puissance, la Science, la Volonté, et en L’exemptant de ce qui est impossible à Son Sujet tel que l’impuissance, l’associé, la localisation et en connaissant ce qui est possible à Son Sujet comme créer une chose ou anéantir une autre.
– Reconnaître que notre raison est incapable de connaître la réalité de Allâh est la connaissance de la réalité de la foi en Allâh. C’est-à-dire si l’être humain connaît Allâh, et la connaissance de Allâh a lieu par le fait de connaître ce qui est obligatoire à Son sujet, ce qui est impossible à Son sujet et ce qui est possible à Son sujet. Si la personne connaît donc Allâh comme il se doit et ce par le fait de croire que Allâh existe et qu’Il ne ressemble pas aux créatures, et que la personne ne peut pas L’imaginer dans son esprit, et s’en tient à cela sans chercher à parvenir à la réalité de Allâh, sans s’imaginer que Allâh serait quelque chose qui ressemble à l’être humain, à un volume lumineux, à un corps au-dessus du Trône ou autre chose de la sorte, on dit de lui qu’il a connu Allâh et a su la vérité de la foi en Allâh, et qu’il s’est préservé de l’assimilation.
– Le prophète (صلى الله عليه وسلم) a enseigné une règle en or dans le tawhîd, qui est : « لا فكرة في الرب » [ ce qui a pour sens : ] « On n’imagine pas Allâh (Ar-Rabb) » [ Rapporté par Al-Baghawi ] et également rapporté par As-Souyoûti, Ad-Dâraqoutni et d’autres.
– Certains savants ont d’ailleurs dit : « Quoi que tu imagines en ton esprit Allâh n’est pas ainsi » .
– Egalement ‘Abdou l-Lâh Ibnou ‘Abbas (رضي الله عنه) a dit : «تفكّروا في خلق الله ولا تفكّروا في ذات الله » ce qui a pour sens : « Méditez sur la création de Allâh mais ne méditez pas sur Allâh Lui-même » [rapporté par Al-Bayhaqi].
– Cette parole de Aboû Bakr (رضي الله عنه) a été rapportée en partie par le Mouhaddith, le Faqîh, le Spécialiste de la science des fondements (al-Ousoûli) Badrou d-Dîn Az-Zarkachi Al-Misri Ach-Châfi’i, né en 745 et décédé en 794 de l’hégire (رحمه الله).', '3aqidah, abou, ahlou s-sounnah, allah'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = '﴾ وَلاَ يُحِيطُونَ بِهِ عِلْمًا ﴿');

COMMIT;
